mapper.insert:
	/** UsptCnvnChangeReqDao.insert */
insert into uspt_cnvn_change_req (
				 cnvn_change_req_id
				,bsns_cnvn_id
				,change_iem_div_cd
				,cnvn_change_sttus_cd
				,cnvn_change_type_cd
				,resn_cn
				,creator_id
				,created_dt
			) values (
				 #{cnvnChangeReqId}
				,#{bsnsCnvnId}
				,#{changeIemDivCd}
				,#{cnvnChangeSttusCd}
				,#{cnvnChangeTypeCd}
				,#{resnCn}
				,#{creatorId}
				,#{createdDt}
			)

mapper.update:
		/** UsptCnvnChangeReqDao.update */
			update uspt_cnvn_change_req
				 set change_iem_div_cd			= #{changeIemDivCd}
					 ,cnvn_change_sttus_cd		= #{cnvnChangeSttusCd}
					 ,cnvn_change_type_cd		=	#{cnvnChangeTypeCd}
					 ,resn_cn							= #{resnCn}
   		 where cnvn_change_req_id = #{cnvnChangeReqId}
      		and bsns_cnvn_id           = #{bsnsCnvnId}

		/** UsptCnvnChangeReqDao.updateCnvnChangeSttus */
			update uspt_cnvn_change_req
				 set cnvn_change_sttus_cd		= #{cnvnChangeSttusCd}
   		    where cnvn_change_req_id 		= #{cnvnChangeReqId}

mapper.select:
/** UsptCnvnChangeReqDao.selectCnvnChangeReqListAdmin */ select a.* from( select row_number() over (order by uccr.created_dt desc) as rn , uccr.cnvn_change_sttus_cd /*협약변경상태-처리상태*/ , fn_cmm_get_code_nm('CNVN_CHANGE_STTUS', uccr.cnvn_change_sttus_cd) as cnvn_change_sttus_nm /*협약변경상태명-처리상태*/ , ubpa.receipt_no /*접수번호*/ , ubpd.task_nm_ko as task_nm_ko /*과제명*/ , uccr.cnvn_change_type_cd /*협약변경유형코드(G:CNVN_CHANGE_TYPE)*/ , fn_cmm_get_code_nm('CNVN_CHANGE_TYPE', uccr.cnvn_change_type_cd) as cnvn_change_type_nm /*협약변경유형코드*/ , uccr.change_iem_div_cd /*협약변경항목구분*/ , fn_cmm_get_code_nm('CHANGE_IEM_DIV', uccr.change_iem_div_cd) as change_iem_div_nm /*협약변경항목구분명*/ , ubpd.member_id /*사업자ID*/ , (select cm.member_nm from cmmt_member cm where cm.member_id = ubpd.member_id ) as member_nm /*사업자명(주관사명)*/ , to_char(uccr.created_dt ,'yyyy-mm-dd') as req_de /*신청일*/ , uccr.cnvn_change_req_id /*협약변경요청ID*/ , uccr.bsns_cnvn_id /*사업협약ID */ , ubpd.bsns_plan_doc_id /*사업계획서ID*/ , ubpd.bsns_slctn_ID /*사업선정대상ID */ from uspt_bsns ub /**사업*/ inner join uspt_bsns_pblanc ubp /**사업공고*/ on ub.bsns_cd = ubp.bsns_cd and ubp.enabled = true inner join uspt_bsns_pblanc_applcnt ubpa /**사업공고신청자*/ on ubp.pblanc_id = ubpa.pblanc_id inner join uspt_bsns_cnvn ubc /*사업협약*/ on ubpa.apply_id = ubc.apply_id inner join uspt_bsns_plan_doc ubpd /**사업계획서*/ on ubc.bsns_plan_doc_id = ubpd.bsns_plan_doc_id inner join uspt_cnvn_change_req uccr /**협약변경요청*/ on ubc.bsns_cnvn_id = uccr.bsns_cnvn_id where 1=1
and uccr.cnvn_change_sttus_cd = #{cnvnChangeSttusCd} /*협약변경상태*/
and uccr.cnvn_change_type_cd = #{cnvnChangeTypeCd} /*협약변경유형코드*/
and uccr.change_iem_div_cd = #{changeIemDivCd} /*협약변경항목구분*/
and ubpd.task_nm_ko like concat('%', #{taskNmKo}, '%') /*과제명*/
) a where 1=1
and a.member_nm = #{memberNm} /*사업자명*/
offset #{beginRowNum} -1 limit #{itemsPerPage}

/** UsptCnvnChangeReqDao.selectProcessHistList */ select a.* from( select ubpa.receipt_no /*접수번호*/ , ubpd.task_nm_ko as task_nm_ko /*과제명*/ , ub.bsns_year /*사업년도*/ , ub.bsns_nm /*사업명*/ , (select cm.member_nm from cmmt_member cm where cm.member_id = ubpd.member_id ) as member_nm /*사업자명(주관사명)*/ , uccr.bsns_cnvn_id /*사업협약ID */ from uspt_bsns ub /**사업*/ inner join uspt_bsns_pblanc ubp /**사업공고*/ on ub.bsns_cd = ubp.bsns_cd and ubp.enabled = true inner join uspt_bsns_pblanc_applcnt ubpa /**사업공고신청자*/ on ubp.pblanc_id = ubpa.pblanc_id inner join uspt_bsns_cnvn ubc /*사업협약*/ on ubpa.apply_id = ubc.apply_id inner join uspt_bsns_plan_doc ubpd /**사업계획서*/ on ubc.bsns_plan_doc_id = ubpd.bsns_plan_doc_id inner join uspt_cnvn_change_req uccr /**협약변경요청*/ on ubc.bsns_cnvn_id = uccr.bsns_cnvn_id where 1=1
and ub.bsns_year = #{bsnsYear} /*사업년도*/
and ub.bsns_nm like concat('%', #{bsnsNm}, '%') /*사업명*/
and ubpd.task_nm_ko like concat('%', #{taskNmKo}, '%') /*과제명*/
and ubpd.task_nm_ko like concat('%', #{taskNmKo}, '%') /*접수번호*/
) a where 1=1
and a.member_nm = #{memberNm} /*사업자명*/
and a.bsns_cnvn_id = #{bsnsCnvnId} /*사업협약ID*/
group by a.receipt_no, a.task_nm_ko, a.bsns_year, a.bsns_nm, a.member_nm, a.bsns_cnvn_id offset #{beginRowNum} -1 limit #{itemsPerPage}

/** UsptCnvnChangeReqDao.selectProcessHistList */ select a.* from( select row_number() over (order by uccr.created_dt desc) as rn , uccr.cnvn_change_sttus_cd /*협약변경상태-처리상태*/ , fn_cmm_get_code_nm('CNVN_CHANGE_STTUS', uccr.cnvn_change_sttus_cd) as cnvn_change_sttus_nm /*협약변경상태명-처리상태*/ , ubpa.receipt_no /*접수번호*/ , ubpd.task_nm_ko as task_nm_ko /*과제명*/ , uccr.cnvn_change_type_cd /*협약변경유형코드(G:CNVN_CHANGE_TYPE)*/ , fn_cmm_get_code_nm('CNVN_CHANGE_TYPE', uccr.cnvn_change_type_cd) as cnvn_change_type_nm /*협약변경유형코드*/ , uccr.change_iem_div_cd /*협약변경항목구분*/ , fn_cmm_get_code_nm('CHANGE_IEM_DIV', uccr.change_iem_div_cd) as change_iem_div_nm /*협약변경항목구분명*/ , ubpd.member_id /*사업자ID*/ , (select cm.member_nm from cmmt_member cm where cm.member_id = ubpd.member_id ) as member_nm /*사업자명(주관사명)*/ , to_char(uccr.created_dt ,'yyyy-mm-dd') as req_de /*신청일*/ , ub.bsns_year /*사업년도*/ , ub.bsns_nm /*사업명*/ , uccr.cnvn_change_req_id /*협약변경요청ID*/ , uccr.bsns_cnvn_id /*사업협약ID */ , ubpd.bsns_plan_doc_id /*사업계획서ID*/ , ubpd.bsns_slctn_ID /*사업선정대상ID */ from uspt_bsns ub /**사업*/ inner join uspt_bsns_pblanc ubp /**사업공고*/ on ub.bsns_cd = ubp.bsns_cd and ubp.enabled = true inner join uspt_bsns_pblanc_applcnt ubpa /**사업공고신청자*/ on ubp.pblanc_id = ubpa.pblanc_id inner join uspt_bsns_cnvn ubc /*사업협약*/ on ubpa.apply_id = ubc.apply_id inner join uspt_bsns_plan_doc ubpd /**사업계획서*/ on ubc.bsns_plan_doc_id = ubpd.bsns_plan_doc_id inner join uspt_cnvn_change_req uccr /**협약변경요청*/ on ubc.bsns_cnvn_id = uccr.bsns_cnvn_id where 1=1
and ub.bsns_year = #{bsnsYear} /*사업년도*/
and ub.bsns_nm like concat('%', #{bsnsNm}, '%') /*사업명*/
and ubpd.task_nm_ko like concat('%', #{taskNmKo}, '%') /*과제명*/
and ubpd.task_nm_ko like concat('%', #{taskNmKo}, '%') /*접수번호*/
) a where 1=1
and a.member_nm = #{memberNm} /*사업자명*/
offset #{beginRowNum} -1 limit #{itemsPerPage}
